def bell_number_partitions(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Use dynamic programming to compute Bell numbers
    # B(n) = sum of Stirling numbers of the second kind S(n, k) for k from 0 to n
    # We'll use the recurrence: B(n+1) = sum_{k=0}^{n} C(n,k) * B(k)

    bell = [0] * (n + 1)
    bell[0] = 1

    for i in range(1, n + 1):
        bell[i] = 0
        for j in range(i):
            bell[i] += comb(i - 1, j) * bell[j]

    return bell[n]

def comb(n, k):
    if k < 0 or k > n:
        return 0
    if k == 0 or k == n:
        return 1
    k = min(k, n - k)  # Take advantage of symmetry
    result = 1
    for i in range(k):
        result = result * (n - i) // (i + 1)
    return result

