# Calculate alternating sum of digits
alt_sum = 0
for i, digit in enumerate(s):
    digit_val = int(digit)
    if i % 2 == 0:
        alt_sum += digit_val
    else:
        alt_sum -= digit_val
# A number is divisible by 11 if the alternating sum is divisible by 11
return alt_sum % 11 == 0

