seq = [0] * (n + 1)
seq[1] = 1
seq[2] = 1

# Fill the sequence using the recurrence relation
for i in range(3, n + 1):
    seq[i] = seq[seq[i - 1]] + seq[i - seq[i - 1]]

return seq[n]

