def max_bitonic_sum(arr):
n = len(arr)
if n == 0:
    return 0

# Initialize arrays to store maximum increasing and decreasing sums
inc = [0] * n
dec = [0] * n

# Fill inc[i]: maximum sum of increasing subsequence ending at i
for i in range(n):
    inc[i] = arr[i]
    for j in range(i):
        if arr[j] < arr[i]:
            inc[i] = max(inc[i], inc[j] + arr[i])

# Fill dec[i]: maximum sum of decreasing subsequence starting at i
for i in range(n - 1, -1, -1):
    dec[i] = arr[i]
    for j in range(i + 1, n):
        if arr[j] < arr[i]:
            dec[i] = max(dec[i], dec[j] + arr[i])

# Find maximum sum of bitonic subsequence
max_sum = 0
for i in range(n):
    # Bitonic sequence with peak at i
    bitonic_sum = inc[i] + dec[i] - arr[i]  # subtract arr[i] once to avoid double counting
    max_sum = max(max_sum, bitonic_sum)

return max_sum

