def catalan(n):
if n <= 1:
    return 1
catalan_nums = [0] * (n + 1)
catalan_nums[0] = catalan_nums[1] = 1
for i in range(2, n + 1):
    for j in range(i):
        catalan_nums[i] += catalan_nums[j] * catalan_nums[i - 1 - j]
return catalan_nums[n]

