def min_swaps_to_convert_binary(s1, s2):
if len(s1) != len(s2):
    raise ValueError("Binary strings must be of equal length")

# Count positions where bits differ
diff_positions = []
for i in range(len(s1)):
    if s1[i] != s2[i]:
        diff_positions.append(i)

# If no differences, no swaps needed
if len(diff_positions) == 0:
    return 0

# Count number of '0' to '1' and '1' to '0' mismatches
# For minimum swaps, we need to pair 0s with 1s
count_0_to_1 = sum(1 for i in diff_positions if s1[i] == '0')
count_1_to_0 = len(diff_positions) - count_0_to_1

# Minimum swaps is the number of mismatches divided by 2
# But we need to handle odd number of mismatches
if count_0_to_1 != count_1_to_0:
    raise ValueError("Cannot convert: unequal number of 0-to-1 and 1-to-0 mismatches")

return len(diff_positions) // 2

def find_kth_element(arr1, arr2, k):
# Handle edge cases
if not arr1:
    return arr2[k - 1]
if not arr2:
    return arr1[k - 1]

# Binary search approach
left1, right1 = 0, len(arr1)
left2, right2 = 0, len(arr2)

while True:
    # Calculate mid points
    mid1 = (left1 + right1) // 2
    mid2 = (left2 + right2) // 2

    # Total elements before mid1 and mid2
    total_before = mid1 + mid2

    # If total elements before mid1 and mid2 is less than k-1
    if total_before < k - 1:
        # Move the smaller of the two mid elements forward
        if mid1 < len(arr1) and (mid2 == len(arr2) or arr1[mid1] <= arr2[mid2]):
            left1 = mid1 + 1
        else:
            left2 = mid2 + 1
    else:
        # Move the larger of the two mid elements backward
        if mid1 > 0 and (mid2 == 0 or arr1[mid1 - 1] >= arr2[mid2 - 1]):
            right1 = mid1
        else:
            right2 = mid2

