def wind_chill_index(velocity, temperature):
"""
Calculate the wind chill index rounded to the next integer.

Parameters:
velocity (float): Wind velocity in km/h
temperature (float): Temperature in Celsius

Returns:
int: Wind chill index rounded to the next integer
"""
if temperature > 10:
    return int(temperature)

wind_chill = 13.12 + 0.6215 * temperature - 11.37 * (velocity ** 0.16) + 0.3965 * temperature * (velocity ** 0.16)
return int(wind_chill + 0.5)

