def find_substring_occurrences(text, substrings, case_sensitive=True, return_positions=True):
if not text or not substrings:
    return None

results = {}
for substring in substrings:
    if not substring:
        continue
    occurrences = []
    start = 0
    while True:
        if case_sensitive:
            pos = text.find(substring, start)
        else:
            pos = text.lower().find(substring.lower(), start)
        if pos == -1:
            break
        occurrences.append(pos)
        start = pos + 1

    if occurrences:
        results[substring] = occurrences if return_positions else len(occurrences)
    else:
        results[substring] = None

# If any substring has no match, return None
if any(val is None for val in results.values()):
    return None

return results

