def rgb_to_hsv(r, g, b):
r, g, b = r / 255.0, g / 255.0, b / 255.0
max_val = max(r, g, b)
min_val = min(r, g, b)
diff = max_val - min_val

if max_val == 0:
    h = 0
elif max_val == r:
    h = (60 * ((g - b) / diff) + 360) % 360
elif max_val == g:
    h = (60 * ((b - r) / diff) + 120) % 360
else:
    h = (60 * ((r - g) / diff) + 240) % 360

if max_val == 0:
    s = 0
else:
    s = diff / max_val

v = max_val

return h, s, v

