def count_rotations(arr):
if not arr:
    return 0

left, right = 0, len(arr) - 1
n = len(arr)

while left <= right:
    if arr[left] <= arr[right]:
        return left

    mid = (left + right) // 2
    next_mid = (mid + 1) % n
    prev_mid = (mid - 1 + n) % n

    if arr[mid] <= arr[next_mid] and arr[mid] <= arr[prev_mid]:
        return mid

    if arr[mid] <= arr[right]:
        right = mid - 1
    else:
        left = mid + 1

return 0

