# Flatten all values to count frequencies
def flatten_values(obj):
    if isinstance(obj, dict):
        for v in obj.values():
            yield from flatten_values(v)
    elif isinstance(obj, list):
        for item in obj:
            yield from flatten_values(item)
    else:
        yield obj

# Count frequencies of all values
