def reverse_matching_words(text):
    words = text.split()
    matching_words = [word for word in words if re.fullmatch(pattern, word)]
    non_matching_words = [word for word in words if not re.fullmatch(pattern, word)]

    # Reverse the order of matching words while preserving non-matching word order
    reversed_matching = matching_words[::-1]

    # Reconstruct the sentence with reversed matching words and original non-matching words
    result_words = []
    matching_idx = 0
    non_matching_idx = 0

    for word in words:
        if re.fullmatch(pattern, word):
            result_words.append(reversed_matching[matching_idx])
            matching_idx += 1
        else:
            result_words.append(non_matching_words[non_matching_idx])
            non_matching_idx += 1

    return ' '.join(result_words)

df_copy = df.copy()
df_copy[column_name] = df_copy[column_name].astype(str).apply(reverse_matching_words)
