            ['ping', '-c', '1', '-W', '2', str(ip)],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )
        stdout, stderr = process.communicate()
        if process.returncode == 0:
            results[ip_str] = True
        else:
            results[ip_str] = False
    except subprocess.CalledProcessError as e:
        raise e
    except Exception as e:
        # Re-raise any other subprocess-related errors as CalledProcessError
        raise subprocess.CalledProcessError(returncode=1, cmd=['ping', str(ip)], output=str(e).encode())

return results

